#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#define MAX_N 14
#define MAX_D 16 * MAX_N
int N, D;
int start[MAX_N];
int visited[(1 << MAX_N)];
int path[(1 << MAX_N)][MAX_N];
int path_len;
void backtrack(int depth) {
    if (depth == (1 << N)) {
        // found a path
        for (int i = 0; i < path_len; i++) {
            for (int j = 0; j < N; j++) {
                printf("%d ", path[i][j]);
            }
            printf("\n");
        }
        return;
    }
    for (int i = 0; i < (1 << N); i++) {
        if (!visited[i]) {
            int distance = 0;
            for (int j = 0; j < N; j++) {
                distance += (path[depth - 1][j] - (i >> j & 1) * 2 + 1) * (path[depth - 1][j] - (i >> j & 1) * 2 + 1);
            }
            if (distance <= D) {
                visited[i] = 1;
                for (int j = 0; j < N; j++) {
                    path[depth][j] = (i >> j & 1) * 2 - 1;
                }
                path_len++;
                backtrack(depth + 1);
                path_len--;
                for (int j = 0; j < N; j++) {
                    path[depth][j] = 0;
                }
                visited[i] = 0;
            }
        }
    }
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &D);
        for (int i = 0; i < N; i++) {
            scanf("%d", &start[i]);
        }
        for (int i = 0; i < (1 << N); i++) {
            visited[i] = 0;
        }
        path_len = 1;
        for (int i = 0; i < N; i++) {
            path[0][i] = start[i];
        }
        backtrack(1);
        printf("-2\n");
    }
    return 0;
}

